	----17/12/2008----------------
	v_denominator		 NUMBER;
	CURSOR cur_age_reduction_denom IS
	SELECT denominator
	FROM PEN_AGE_REDUCTION_DENOM
	WHERE VALIDITY_DATE <= :P_FACTITIOUS_DATE
	ORDER BY VALIDITY_DATE DESC;
	-------------------------------

begin


  OPEN cur_age_reduction_denom;
	FETCH cur_age_reduction_denom
	INTO v_denominator;
	CLOSE cur_age_reduction_denom;
				


  OPEN CUR_SF499;
  FETCH CUR_SF499
  INTO SF499_VALUE;
  CLOSE CUR_SF499;

	IF SF499_VALUE = '00001' THEN 
 		  	OPEN cur_SF00507;
		  	FETCH cur_SF00507
		  	INTO SF507_VALUE;
		  	CLOSE cur_SF00507;

		  IF :CF_INS_DATE >= TO_DATE('1/1/2003','DD/MM/RRRR') THEN 
		  	IF SF507_VALUE IS NOT NULL THEN 
  		  	RETURN (TO_CHAR(SF507_VALUE)||'/'||v_denominator);--'/267');
		  	ELSE 
		  		RETURN ' ';
        END IF;
		  ELSE 
		    IF SF507_VALUE IS NOT NULL THEN 		
	   	  	RETURN (TO_CHAR(SF507_VALUE)||'/'||v_denominator);--'/200');
		    ELSE
		      RETURN ' ';	
        END IF;
		  END IF;
	ELSE
 		  	OPEN cur_SF00508;
		  	FETCH cur_SF00508
		  	INTO SF508_VALUE;
		  	CLOSE cur_SF00508;

        IF SF508_VALUE IS NOT NULL THEN  		  	
  		  	RETURN TO_CHAR(SF508_VALUE) || '%';
        ELSE
        	RETURN ' ';	
        END IF;
  END IF;
end;









	

