total_days_h, 
flg_kind, 
pen_class,
amnt1,
amnt2,
amnt1+amnt2 tot_amnt,
perc,
amnt3,
LOWEST_CALC_DAYS,
LOWEST_ASS_TOTAL_PRCN,
LOWEST_AMOUNT
from pen_account_rep
where account_no=:P_ACC_ACCOUNT_NO_DIR;

v_cur_pen_account_rep  cur_pen_account_rep%rowtype;

my_total_days1  number;
my_total_days2  number;
my_total_days_h number;
my_text1				varchar2(512);
my_text2				varchar2(512);
my_text3				varchar2(512);
my_text4				varchar2(512);

begin
	
open 	cur_pen_account_rep;
fetch cur_pen_account_rep
into  v_cur_pen_account_rep;
close cur_pen_account_rep;

my_total_days1	:=floor(v_cur_pen_account_rep.total_days/300)*300;
my_total_days2	:=floor((v_cur_pen_account_rep.total_days-10500)/300)*300;
my_total_days_h	:=floor(v_cur_pen_account_rep.total_days_h/300)*300;


IF :CF_PRODUCT_CODE = '00003' THEN

	
	if v_cur_pen_account_rep.flg_kind='1' then
		 	my_text1:='ΤO ΒΑΣΙΚΟ ΠΟΣΟ ΑΝΑΛΥΕΤΑΙ ΩΣ ΕΞΗΣ: '||round(v_cur_pen_account_rep.pen_class,2)||' *  2% * ( '||my_total_days1||'/300 '||' ) '||' = '||round(v_cur_pen_account_rep.amnt1,2);
	elsif v_cur_pen_account_rep.flg_kind='2' then
			my_text1:='ΤO ΒΑΣΙΚΟ ΠΟΣΟ ΑΝΑΛΥΕΤΑΙ ΩΣ ΕΞΗΣ: '||'0.02 * '||'10500/300* '||round(v_cur_pen_account_rep.pen_class,2)||' + '||'0.03* '||my_total_days2||'/300 '||'*'||round(v_cur_pen_account_rep.pen_class,2)||'='||round(v_cur_pen_account_rep.amnt1,2);
	else
			my_text1:='ΤO ΒΑΣΙΚΟ ΠΟΣΟ ΑΝΑΛΥΕΤΑΙ ΩΣ ΕΞΗΣ: '||round(v_cur_pen_account_rep.pen_class,2)||' *  2% * ( '||my_total_days1||'/300 '||' ) '||' = '||round(v_cur_pen_account_rep.amnt1,2);
	end if;
	
--	if v_cur_pen_account_rep.total_days_h<>0 then
--		 my_text2:='TΟ ΠΟΣΟ ΤΗΣ ΠΡΟΣΑΥΞΗΣΗΣ ΛΟΓΩ ΒΑΡΕΩΝ ΑΝΑΛΥΕΤΑΙ ΩΣ ΕΞΗΣ : '||'0.02 * 1.2 * '||my_total_days_h||'/300 '||' * '||round(v_cur_pen_account_rep.pen_class,2)||'='||round(v_cur_pen_account_rep.amnt2,2);
--		 my_text1:=my_text1||chr(10)||my_text2;
--	end if;	 
		 
	IF NVL(round(v_cur_pen_account_rep.amnt3,2),0) != NVL(round(v_cur_pen_account_rep.amnt1,2),0) + NVL(round(v_cur_pen_account_rep.amnt2,2),0) THEN
			my_text3:='ΤΟ ΟΠΟΙΟ ΜΕ ΤΗΝ EΤΗΣΙΑ ΑΥΞΗΣΗ '||v_cur_pen_account_rep.perc*100||'% ΔΙΑΜΟΡΦΩΝΕΤΑΙ ΣΕ: '||round(v_cur_pen_account_rep.amnt3,2);
			my_text1:=my_text1||chr(10)||my_text3;
	END IF;
	
	IF v_cur_pen_account_rep.LOWEST_CALC_DAYS IS NOT NULL THEN
		 my_text4:='ΤO ΚΑΤΩΤΑΤΟ ΠΟΣΟ ΑΝΑΛΥΕΤΑΙ ΩΣ ΕΞΗΣ: '||' 80% * (548,75 * 70% + αυξήσεις συντάξεων('||v_cur_pen_account_rep.LOWEST_CALC_DAYS||') ) * ('||:p_percentage||'/'||v_cur_pen_account_rep.LOWEST_ASS_TOTAL_PRCN||') = '||ROUND(v_cur_pen_account_rep.LOWEST_AMOUNT*:p_percentage/v_cur_pen_account_rep.LOWEST_ASS_TOTAL_PRCN,2);
		 my_text1:=my_text1||CHR(10)||my_text4;
	END IF;	
	
ELSE
	
	IF v_cur_pen_account_rep.LOWEST_CALC_DAYS IS NOT NULL THEN
		 my_text1:='ΤO ΚΑΤΩΤΑΤΟ ΠΟΣΟ ΑΝΑΛΥΕΤΑΙ ΩΣ ΕΞΗΣ: '||' 80% * (548,75 * 70% + αυξήσεις συντάξεων('||v_cur_pen_account_rep.LOWEST_CALC_DAYS||') ) * ('||:p_percentage||'/'||v_cur_pen_account_rep.LOWEST_ASS_TOTAL_PRCN||') = '||ROUND(v_cur_pen_account_rep.LOWEST_AMOUNT*:p_percentage/v_cur_pen_account_rep.LOWEST_ASS_TOTAL_PRCN,2);
	END IF;	
	
END IF;

return my_text1;
	
	
  
end;

